mapper.select:
/* grpInsrMapper.getGrpInsrCdList */
WITH TMP AS ( SELECT REPLACE(SUBSTR(INSR_CD, START_POS, END_POS - START_POS), ',', '') AS INSR_CD FROM ( SELECT INSR_CD , DECODE(LEVEL, 1, 1, INSTR(INSR_CD, ',', 1, LEVEL-1)) AS START_POS , INSTR(INSR_CD, ',', 1, LEVEL) AS END_POS , LEVEL AS LVL FROM ( SELECT INSR_CD || ',' AS INSR_CD , LENGTH(INSR_CD) AS ORI_LEN , LENGTH(REPLACE(INSR_CD, ',', '')) AS NEW_LEN FROM MSP_GRP_INSR_MST WHERE SEQ = #{seq} ) CONNECT BY LEVEL <= ORI_LEN - NEW_LEN + 1 ) A )
SELECT DECODE(A.INSR_CD, NULL, 0, 1) AS CHK , B.CD_VAL AS INSR_CD , B.CD_DSC AS INSR_NM FROM TMP A , CMN_GRP_CD_MST B WHERE A.INSR_CD(+) = B.CD_VAL AND B.GRP_ID = 'CMN0246' AND B.USG_YN = 'Y' AND B.ETC2 = 'Y' ORDER BY B.CD_VAL

mapper.insert:

	SELECT NVL(MAX(SEQ) + 1, 1) AS seq FROM MSP_GRP_INSR_MST

/* grpInsrMapper.insertGrpInsrMst */
INSERT INTO MSP_GRP_INSR_MST (
    SEQ
    , GRP_INSR_NM
    , STRT_DT
    , END_DT
    , USG_YN
    , INSR_CD
    , INSR_NM
    , EXCEPT_RATE
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
) VALUES (
    #{seq}
    , #{grpInsrNm, jdbcType=VARCHAR}
    , #{strtDt, jdbcType=VARCHAR}
    , #{endDt, jdbcType=VARCHAR}
    , DECODE(#{usgYn, jdbcType=VARCHAR}, '0', 'N', #{usgYn, jdbcType=VARCHAR})
    , #{insrCds, jdbcType=VARCHAR}
    , #{insrNms, jdbcType=VARCHAR}
    , #{exceptRate, jdbcType=VARCHAR}
    , #{sessionUserId, jdbcType=VARCHAR}
    , SYSDATE
    , #{sessionUserId, jdbcType=VARCHAR}
    , SYSDATE
)

mapper.update:
/* grpInsrMapper.updateGrpInsrMst */
UPDATE  MSP_GRP_INSR_MST
SET     USG_YN = DECODE(#{usgYn, jdbcType=VARCHAR}, '0', 'N', #{usgYn, jdbcType=VARCHAR})
WHERE   SEQ = #{seq}

mapper.select:
/* grpInsrMapper.getGrpInsrCombo */
WITH TMP AS ( SELECT DISTINCT REPLACE(SUBSTR(INSR_CD, START_POS, END_POS - START_POS), ',', '') AS INSR_CD FROM ( SELECT DISTINCT INSR_CD , DECODE(LEVEL, 1, 1, INSTR(INSR_CD, ',', 1, LEVEL-1)) AS START_POS , INSTR(INSR_CD, ',', 1, LEVEL) AS END_POS , LEVEL AS LVL FROM ( SELECT A.INSR_CD || ',' AS INSR_CD , LENGTH(A.INSR_CD) AS ORI_LEN , LENGTH(REPLACE(A.INSR_CD, ',', '')) AS NEW_LEN FROM MSP_GRP_INSR_MST A WHERE NVL(#{reqInDay}, TO_CHAR(SYSDATE, 'YYYYMMDD')) BETWEEN A.STRT_DT AND A.END_DT AND A.USG_YN = 'Y' ) CONNECT BY LEVEL <= ORI_LEN - NEW_LEN + 1 ) )
SELECT A.INSR_CD AS VALUE , B.CD_DSC AS TEXT FROM TMP A , CMN_GRP_CD_MST B WHERE A.INSR_CD = B.CD_VAL AND B.GRP_ID = 'CMN0246' AND B.USG_YN = 'Y' AND B.ETC2 = 'Y' ORDER BY B.CD_VAL
